import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-default',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <n-datepicker
      [(nValue)]="value"
      nPlaceholder="Selecione uma data"
      class="w-full max-w-sm"
    />
  `,
})
export class DatepickerDefaultDemo {
  value = signal<Date | null>(null);
}

import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-disabled-weekends',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <n-datepicker
      [(nValue)]="value"
      nLabel="Dia útil"
      nHint="Sábados e domingos não estão disponíveis"
      [nDisabledDate]="isWeekend"
      class="w-full max-w-sm"
    />
  `,
})
export class DatepickerDisabledWeekendsDemo {
  value = signal<Date | null>(null);
  readonly isWeekend = (d: Date) => d.getDay() === 0 || d.getDay() === 6;
}

import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-error',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <n-datepicker
      [(nValue)]="value"
      nLabel="Data de início"
      nPlaceholder="Selecione"
      nError="Esta data é obrigatória"
      class="w-full max-w-sm"
    />
  `,
})
export class DatepickerErrorDemo {
  value = signal<Date | null>(null);
}

import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-min-max',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <n-datepicker
      [(nValue)]="value"
      nLabel="Janela de reserva"
      nHint="Disponível apenas nos próximos 30 dias"
      [nMin]="min"
      [nMax]="max"
      class="w-full max-w-sm"
    />
  `,
})
export class DatepickerMinMaxDemo {
  value = signal<Date | null>(null);
  readonly min = new Date();
  readonly max = (() => {
    const d = new Date();
    d.setDate(d.getDate() + 30);
    return d;
  })();
}

import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-sizes',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <div class="flex w-full max-w-sm flex-col gap-3">
      <n-datepicker [(nValue)]="a" nSize="sm" nPlaceholder="Pequeno" />
      <n-datepicker [(nValue)]="b" nSize="default" nPlaceholder="Padrão" />
      <n-datepicker [(nValue)]="c" nSize="lg" nPlaceholder="Grande" />
    </div>
  `,
})
export class DatepickerSizesDemo {
  a = signal<Date | null>(null);
  b = signal<Date | null>(null);
  c = signal<Date | null>(null);
}

import { Component } from '@angular/core';
import { FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-with-form',
  standalone: true,
  imports: [DatepickerComponent, ReactiveFormsModule],
  template: `
    <form [formGroup]="form" class="flex w-full max-w-sm flex-col gap-3">
      <n-datepicker
        formControlName="date"
        nLabel="Agendamento"
        nPlaceholder="Selecione uma data"
        [nRequired]="true"
        [nError]="form.controls.date.touched && form.controls.date.invalid ? 'Selecione uma data' : null"
      />
      <p class="text-muted-foreground text-sm">
        Selecionado:
        <span class="text-foreground font-medium">
          {{ form.controls.date.value ? form.controls.date.value.toLocaleDateString() : 'nenhum' }}
        </span>
      </p>
    </form>
  `,
})
export class DatepickerWithFormDemo {
  readonly form = new FormGroup({
    date: new FormControl<Date | null>(null, Validators.required),
  });
}

import { Component, signal } from '@angular/core';
import { DatepickerComponent } from '../datepicker.component';

@Component({
  selector: 'demo-datepicker-with-label',
  standalone: true,
  imports: [DatepickerComponent],
  template: `
    <n-datepicker
      [(nValue)]="value"
      nLabel="Data de nascimento"
      nPlaceholder="dd/mm/aaaa"
      nHint="Usaremos para verificar idade"
      class="w-full max-w-sm"
    />
  `,
})
export class DatepickerWithLabelDemo {
  value = signal<Date | null>(null);
}
